	private static List<long[]> leftRows(int rows, long groupId) {
		List<long[]> values = new ArrayList<>();
		for (int i = 1; i <= rows; i++) {
			values.add(new long[] { i, groupId, LmdbValue.UNKNOWN_ID });
		}
		return values;
	}

	private static List<Long> range(int startInclusive, int endInclusive) {
		List<Long> values = new ArrayList<>();
		for (int i = startInclusive; i <= endInclusive; i++) {
			values.add((long) i);
		}
		return values;
	}

